using System.Text;
using SecretLead.Models;

namespace SecretLead.Services;

/// <summary>
/// A small hand-rolled CSV reader (RFC 4180-ish: quoted fields, embedded
/// commas/newlines, <c>""</c> as an escaped quote) — no third-party CSV
/// library, per README.md §2/§15.
/// </summary>
public static class CsvParser
{
    public static CsvTable Parse(string csvText)
    {
        var rows = ParseRows(csvText);

        if (rows.Count == 0)
        {
            throw new CsvFormatException("CSV file is empty.");
        }

        var headers = rows[0];
        if (headers.Count == 0 || headers.All(h => h.Length == 0))
        {
            throw new CsvFormatException("CSV file has no header row.");
        }

        var dataRows = new List<IReadOnlyDictionary<string, string>>();

        for (var r = 1; r < rows.Count; r++)
        {
            var rawRow = rows[r];

            // Skip a fully-blank trailing row (common at the end of
            // exported CSVs) rather than importing a garbage record.
            if (rawRow.Count == 1 && rawRow[0].Length == 0)
            {
                continue;
            }

            var rowValues = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            for (var c = 0; c < headers.Count; c++)
            {
                rowValues[headers[c]] = c < rawRow.Count ? rawRow[c] : string.Empty;
            }

            dataRows.Add(rowValues);
        }

        return new CsvTable
        {
            Headers = headers,
            Rows = dataRows,
        };
    }

    private static List<List<string>> ParseRows(string text)
    {
        var rows = new List<List<string>>();
        var currentRow = new List<string>();
        var field = new StringBuilder();
        var inQuotes = false;
        var sawAnyContentOnRow = false;
        var i = 0;
        var length = text.Length;

        void FinishField()
        {
            currentRow.Add(field.ToString());
            field.Clear();
        }

        void FinishRow()
        {
            FinishField();
            rows.Add(currentRow);
            currentRow = [];
            sawAnyContentOnRow = false;
        }

        while (i < length)
        {
            var c = text[i];

            if (inQuotes)
            {
                if (c == '"')
                {
                    if (i + 1 < length && text[i + 1] == '"')
                    {
                        field.Append('"');
                        i += 2;
                    }
                    else
                    {
                        inQuotes = false;
                        i++;
                    }
                }
                else
                {
                    field.Append(c);
                    i++;
                }

                continue;
            }

            switch (c)
            {
                case '"':
                    inQuotes = true;
                    sawAnyContentOnRow = true;
                    i++;
                    break;

                case ',':
                    FinishField();
                    sawAnyContentOnRow = true;
                    i++;
                    break;

                case '\r':
                    FinishRow();
                    i++;
                    if (i < length && text[i] == '\n')
                    {
                        i++;
                    }

                    break;

                case '\n':
                    FinishRow();
                    i++;
                    break;

                default:
                    field.Append(c);
                    sawAnyContentOnRow = true;
                    i++;
                    break;
            }
        }

        if (field.Length > 0 || currentRow.Count > 0 || sawAnyContentOnRow)
        {
            FinishRow();
        }

        return rows;
    }
}
